class Solution:
    def alternatingXOR(self, nums, target1, target2):
        MOD = 10 ** 9 + 7
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] ^ nums[i]
        targets = [target1, target2]
        dp = [[0, 0] for _ in range(n + 1)]
        dp[0][0] = 1
        for j in range(1, n + 1):
            total = [0, 0]
            for i in range(j):
                for p in (0, 1):
                    if dp[i][p] and (prefix[j] ^ prefix[i]) == targets[p]:
                        total[1 - p] = (total[1 - p] + dp[i][p]) % MOD
            dp[j][0] = total[0]
            dp[j][1] = total[1]
        return (dp[n][0] + dp[n][1]) % MOD

