        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] ^ nums[i]
        targets = (target1, target2)
        map0 = {prefix[0]: 1}
        map1 = {}
        dp0 = 1
        dp1 = 0
        for j in range(1, n + 1):
            pj = prefix[j]
            new1 = map0.get(pj ^ targets[0], 0) % MOD
            new0 = map1.get(pj ^ targets[1], 0) % MOD
            dp0, dp1 = new0, new1
            map0[pj] = (map0.get(pj, 0) + dp0) % MOD
            map1[pj] = (map1.get(pj, 0) + dp1) % MOD
        return (dp0 + dp1) % MOD

