var alternatingXOR = function(nums, target1, target2) {
    const MOD = 1000000007;
    const n = nums.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] ^ nums[i];
    const targets = [target1, target2];
    const map0 = new Map();
    const map1 = new Map();
    map0.set(prefix[0], 1);
    let dp0 = 1, dp1 = 0;
    for (let j = 1; j <= n; j++) {
        const pj = prefix[j];
        const new1 = map0.get(pj ^ targets[0]) || 0;
        const new0 = map1.get(pj ^ targets[1]) || 0;
        dp0 = new0 % MOD;
        dp1 = new1 % MOD;
        map0.set(pj, ((map0.get(pj) || 0) + dp0) % MOD);
        map1.set(pj, ((map1.get(pj) || 0) + dp1) % MOD);
    }
    return (dp0 + dp1) % MOD;
};
